#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <stdexcept>
#include <cstdlib>
#include <cstdio>

std::string exec(const char* cmd) {
    char buffer[128];
    std::string result = "";
    FILE* pipe = popen(cmd, "r");
    if (!pipe) throw std::runtime_error("popen() failed!");
    try {
        while (fgets(buffer, sizeof buffer, pipe) != NULL) {
            result += buffer;
        }
    } catch (...) {
        pclose(pipe);
        throw;
    }
    pclose(pipe);
    return result;
}

int main() {
    std::string cpp_file = "4050.cpp";
    std::string executable = "a.out";
    std::string compile_cmd = "g++ " + cpp_file + " -o " + executable + " 2>&1";

    std::string compile_output = exec(compile_cmd.c_str());
    if (compile_output.find("error:") != std::string::npos || compile_output.find("fatal error:") != std::string::npos) {
        std::cerr << "Compilation failed for " << cpp_file << ":\n" << compile_output << std::endl;
        std::cout << "COMPILATION_FAILED\n" << compile_output << std::endl;
        return 1;
    }

    std::cout << "Compilation successful for " << cpp_file << ".\n";

    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"7", "7 x 1 = 7\n7 x 2 = 14\n7 x 3 = 21\n7 x 4 = 28\n7 x 5 = 35\n7 x 6 = 42\n7 x 7 = 49\n7 x 8 = 56\n7 x 9 = 63\n7 x 10 = 70\n"}
    };

    bool all_passed = true;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& test_case = test_cases[i];
        std::string input = test_case.first;
        std::string expected_output = test_case.second;

        std::string run_cmd = "echo \"" + input + "\" | ./" + executable + " 2>&1";
        std::string actual_output = exec(run_cmd.c_str());

        size_t prompt_pos = actual_output.find("Enter a number: ");
        if (prompt_pos != std::string::npos) {
            actual_output = actual_output.substr(prompt_pos + std::string("Enter a number: ").length());
        }

        if (actual_output == expected_output) {
            std::cout << "Test case " << i + 1 << " passed.\n";
        } else {
            std::cout << "Test case " << i + 1 << " failed.\n";
            std::cout << "Input: " << input << "\n";
            std::cout << "Expected:\n" << expected_output << "\n";
            std::cout << "Actual:\n" << actual_output << "\n";
            all_passed = false;
        }
    }

    if (all_passed) {
        std::cout << "All test cases passed.\n";
    } else {
        std::cout << "Some test cases failed.\n";
        return 1;
    }

    return 0;
}
